import{_ as a,o as t,c as d,a2 as s}from"./chunks/framework.Dvn0Uh9o.js";const u=JSON.parse('{"title":"Validation Lifecycle","description":"","frontmatter":{},"headers":[],"relativePath":"validation/lifecycle.md","filePath":"validation/lifecycle.md","lastUpdated":1783374693000}'),i={name:"validation/lifecycle.md"};function n(o,e,l,r,c,p){return t(),d("div",null,[...e[0]||(e[0]=[s(`<h1 id="validation-lifecycle" tabindex="-1">Validation Lifecycle <a class="header-anchor" href="#validation-lifecycle" aria-label="Permalink to &quot;Validation Lifecycle&quot;">​</a></h1><p>This page explains <strong>when</strong> and <strong>how</strong> validation runs in mobx-react-form, from a single field change all the way through form submission.</p><hr><h2 id="when-validation-fires" tabindex="-1">When Validation Fires <a class="header-anchor" href="#when-validation-fires" aria-label="Permalink to &quot;When Validation Fires&quot;">​</a></h2><p>Validation is triggered by the following lifecycle events. Each can be enabled or disabled via form options.</p><table tabindex="0"><thead><tr><th>Trigger</th><th>Option</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Form init</strong></td><td><code>validateOnInit</code></td><td><code>true</code></td><td>Validate all fields when the form is first created</td></tr><tr><td><strong>Field blur</strong></td><td><code>validateOnBlur</code></td><td><code>true</code></td><td>Validate a field when it loses focus</td></tr><tr><td><strong>Field change</strong></td><td><code>validateOnChange</code></td><td><code>false</code></td><td>Validate a field on every value change</td></tr><tr><td><strong>Change after blur</strong></td><td><code>validateOnChangeAfterInitialBlur</code></td><td><code>false</code></td><td>Validate on change only after the field has been blurred at least once</td></tr><tr><td><strong>Change after submit</strong></td><td><code>validateOnChangeAfterSubmit</code></td><td><code>false</code></td><td>Validate on change only after the form has been submitted at least once</td></tr><tr><td><strong>Form submit</strong></td><td><code>validateOnSubmit</code></td><td><code>true</code></td><td>Validate all fields before submit handlers run</td></tr><tr><td><strong>Clear</strong></td><td><code>validateOnClear</code></td><td><code>false</code></td><td>Validate after clearing field values</td></tr><tr><td><strong>Reset</strong></td><td><code>validateOnReset</code></td><td><code>false</code></td><td>Validate after resetting to default values</td></tr></tbody></table><blockquote><p>The <strong>validateOnChange</strong> options are evaluated per-field in <code>Field.ts</code> (lines ~940-961). They can also be set <strong>per field</strong> via <code>field.$options.validateOnChange</code>.</p></blockquote><hr><h2 id="field-validation-flow" tabindex="-1">Field Validation Flow <a class="header-anchor" href="#field-validation-flow" aria-label="Permalink to &quot;Field Validation Flow&quot;">​</a></h2><p>When a field triggers validation (e.g. on blur), the following happens:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Can skip?</span></span>
<span class="line"><span>   ├── field is deleted &amp;&amp; validateDeletedFields = false   → skip</span></span>
<span class="line"><span>   ├── field is disabled &amp;&amp; validateDisabledFields = false  → skip</span></span>
<span class="line"><span>   ├── field is pristine &amp;&amp; validatePristineFields = false   → skip</span></span>
<span class="line"><span>   └── none of the above                                    → continue</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Reset previous errors?</span></span>
<span class="line"><span>   ├── resetValidationBeforeValidate = true   → resetValidation()</span></span>
<span class="line"><span>   └── resetValidationBeforeValidate = false  → keep previous errors</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Trim value?</span></span>
<span class="line"><span>   ├── validateTrimmedValue = true   → field.trim()</span></span>
<span class="line"><span>   └── validateTrimmedValue = false  → use value as-is</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Run each validation driver (in order):</span></span>
<span class="line"><span>   For each enabled plugin:</span></span>
<span class="line"><span>     driver.validate(field)</span></span>
<span class="line"><span>     if stopValidationOnError &amp;&amp; field.hasError → break</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Show/hide errors:</span></span>
<span class="line"><span>   field.showErrors(showErrors, false)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. Validate related fields:</span></span>
<span class="line"><span>   if related → validate fields listed in field.related</span></span></code></pre></div><h3 id="field-skip-conditions" tabindex="-1">Field skip conditions <a class="header-anchor" href="#field-skip-conditions" aria-label="Permalink to &quot;Field skip conditions&quot;">​</a></h3><ul><li><strong><code>validateDeletedFields</code></strong> (default: <code>false</code>) — soft-deleted fields are skipped</li><li><strong><code>validateDisabledFields</code></strong> (default: <code>false</code>) — disabled fields are skipped</li><li><strong><code>validatePristineFields</code></strong> (default: <code>true</code>) — fields that haven&#39;t been touched</li><li><strong><code>resetValidationBeforeValidate</code></strong> (default: <code>true</code>) — clear error stack before re-validating</li><li><strong><code>validateTrimmedValue</code></strong> (default: <code>false</code>) — trim whitespace before validating</li></ul><h3 id="plugin-execution-order" tabindex="-1">Plugin execution order <a class="header-anchor" href="#plugin-execution-order" aria-label="Permalink to &quot;Plugin execution order&quot;">​</a></h3><p>By default, all enabled drivers run in the order they were registered. You can customize this using <code>validationPluginsOrder</code>:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> options</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  validationPluginsOrder: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;vjf&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;yup&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;zod&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div><p>If <code>stopValidationOnError</code> is <code>true</code>, once a field has an error from one driver, subsequent drivers are skipped for that field.</p><hr><h2 id="submit-flow" tabindex="-1">Submit Flow <a class="header-anchor" href="#submit-flow" aria-label="Permalink to &quot;Submit Flow&quot;">​</a></h2><p>When <code>form.submit()</code> is called:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Exec onSubmit hook (if execOnSubmitHook = true)</span></span>
<span class="line"><span>2. Set $submitting = true, increment $submitted</span></span>
<span class="line"><span>3. Validate?</span></span>
<span class="line"><span>   ├── validateOnSubmit = true   → form.validate({ showErrors: showErrorsOnSubmit })</span></span>
<span class="line"><span>   └── validateOnSubmit = false  → skip validation, resolve immediately</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. After validation resolves:</span></span>
<span class="line"><span>   ├── isValid = true  → exec onSuccess hook</span></span>
<span class="line"><span>   ├── isValid = false → exec onError hook</span></span>
<span class="line"><span>   │                     + if submitThrowsError &amp;&amp; defaultGenericError → invalidate()</span></span>
<span class="line"><span>   └── (hooks skipped if execValidationHooks = false)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Set $submitting = false</span></span>
<span class="line"><span>6. Return the form/field instance</span></span></code></pre></div><h3 id="submit-parameters" tabindex="-1">submit() parameters <a class="header-anchor" href="#submit-parameters" aria-label="Permalink to &quot;submit() parameters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Param</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>validate</code></td><td><code>true</code></td><td>Whether to validate before resolving</td></tr><tr><td><code>execOnSubmitHook</code></td><td><code>true</code></td><td>Whether to fire the <code>onSubmit</code> hook</td></tr><tr><td><code>execValidationHooks</code></td><td><code>true</code></td><td>Whether to fire <code>onSuccess</code> / <code>onError</code> hooks</td></tr></tbody></table><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Minimal submit — skip validation entirely</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">form.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">submit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({}, { validate: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Submit without firing hooks</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">form.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">submit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({}, { execOnSubmitHook: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, execValidationHooks: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span></code></pre></div><hr><h2 id="validation-error-stack" tabindex="-1">Validation Error Stack <a class="header-anchor" href="#validation-error-stack" aria-label="Permalink to &quot;Validation Error Stack&quot;">​</a></h2><p>Each field has a <code>validationErrorStack</code> (array of strings). When a plugin finds a validation error, it pushes the error message onto this stack via <code>field.invalidate(message)</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>validationErrorStack: string[]</span></span></code></pre></div><p>The first error in the stack is displayed as the field&#39;s <code>error</code> property.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>error = validationErrorStack.length ? validationErrorStack[0] : null</span></span></code></pre></div><hr><h2 id="related-options-summary" tabindex="-1">Related Options Summary <a class="header-anchor" href="#related-options-summary" aria-label="Permalink to &quot;Related Options Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>validateOnInit</code></td><td>boolean</td><td><code>true</code></td><td>Validate on form creation</td></tr><tr><td><code>validateOnSubmit</code></td><td>boolean</td><td><code>true</code></td><td>Validate on submit</td></tr><tr><td><code>validateOnBlur</code></td><td>boolean</td><td><code>true</code></td><td>Validate on field blur</td></tr><tr><td><code>validateOnChange</code></td><td>boolean</td><td><code>false</code></td><td>Validate on every value change</td></tr><tr><td><code>validateOnChangeAfterInitialBlur</code></td><td>boolean</td><td><code>false</code></td><td>Validate on change after first blur</td></tr><tr><td><code>validateOnChangeAfterSubmit</code></td><td>boolean</td><td><code>false</code></td><td>Validate on change after first submit</td></tr><tr><td><code>validateOnClear</code></td><td>boolean</td><td><code>false</code></td><td>Validate on clear</td></tr><tr><td><code>validateOnReset</code></td><td>boolean</td><td><code>false</code></td><td>Validate on reset</td></tr><tr><td><code>validateDisabledFields</code></td><td>boolean</td><td><code>false</code></td><td>Validate disabled fields</td></tr><tr><td><code>validateDeletedFields</code></td><td>boolean</td><td><code>false</code></td><td>Validate soft-deleted fields</td></tr><tr><td><code>validatePristineFields</code></td><td>boolean</td><td><code>true</code></td><td>Validate untouched fields</td></tr><tr><td><code>validateTrimmedValue</code></td><td>boolean</td><td><code>false</code></td><td>Trim value before validation</td></tr><tr><td><code>stopValidationOnError</code></td><td>boolean</td><td><code>false</code></td><td>Stop after first driver finds error</td></tr><tr><td><code>validationPluginsOrder</code></td><td>string[]</td><td><code>undefined</code></td><td>Custom driver execution order</td></tr><tr><td><code>resetValidationBeforeValidate</code></td><td>boolean</td><td><code>true</code></td><td>Clear errors before re-validating</td></tr><tr><td><code>validationDebounceWait</code></td><td>number</td><td><code>250</code></td><td>Debounce interval (ms)</td></tr><tr><td><code>validationDebounceOptions</code></td><td>object</td><td><code>{ leading: false, trailing: true }</code></td><td>Debounce leading/trailing config</td></tr><tr><td><code>showErrorsOnInit</code></td><td>boolean</td><td><code>false</code></td><td>Show errors on form init</td></tr><tr><td><code>showErrorsOnSubmit</code></td><td>boolean</td><td><code>true</code></td><td>Show errors on submit</td></tr><tr><td><code>showErrorsOnBlur</code></td><td>boolean</td><td><code>true</code></td><td>Show errors on blur</td></tr><tr><td><code>showErrorsOnChange</code></td><td>boolean</td><td><code>true</code></td><td>Show errors on change</td></tr><tr><td><code>showErrorsOnClear</code></td><td>boolean</td><td><code>false</code></td><td>Show errors on clear</td></tr><tr><td><code>showErrorsOnReset</code></td><td>boolean</td><td><code>true</code></td><td>Show errors on reset</td></tr></tbody></table><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../error-handling">Error Handling</a> — <code>submitThrowsError</code>, <code>defaultGenericError</code>, server error mapping</li><li><a href="./../performance-ssr">Performance &amp; SSR</a> — debounce, lazy triggers</li><li><a href="./../actions/validate">Validation &amp; Submit Actions</a> — programmatic control</li></ul>`,36)])])}const f=a(i,[["render",n]]);export{u as __pageData,f as default};
